// ❌ BAD - old System.Tuple: heap allocation, no names, immutable Item1/Item2
Tuple<string, decimal> GetProductInfo() => Tuple.Create("Widget", 9.99m);
var info = GetProductInfo();
Console.WriteLine(info.Item2); // unclear: what is Item2?

// ✅ GOOD - ValueTuple: struct, named elements, deconstruction
(string Name, decimal Price) GetProductInfo() => ("Widget", 9.99m);
var (name, price) = GetProductInfo();
Console.WriteLine($"{name} costs {price:C}"); // clear and readable

// IEnumerable + IEnumerator manually (what foreach does internally)
IEnumerable<int> seq = new[] { 1, 2, 3 };
using IEnumerator<int> cursor = seq.GetEnumerator();
while (cursor.MoveNext()) Console.Write(cursor.Current + " "); // 1 2 3

// IQueryable: Where builds a SQL WHERE clause, not in-memory filter
IQueryable<Order> query = db.Orders.Where(o => o.Total > 100);

// IAsyncEnumerable: stream rows from EF Core one at a time
await foreach (var order in db.Orders.AsAsyncEnumerable())
    await ProcessAsync(order); // each row processed as it arrives
